using namespace std;

bool isAnagram(string s, string t)
{
    if (s.size() != t.size()) return false;

    unordered_map<char, int> counts;
    for (char c : s) counts[c]++;
    for (char c : t) counts[c]--;

    for (auto &[c, cnt] : counts)
    {
        if (cnt != 0) return false;
    }
    return true;
}

