#include <vector>

using namespace std;

int subarraySum(vector<int> &nums, int k)
{
    int count = 0;

    for (int i = 0; i < nums.size(); i++)
    {
        int sum = 0;
        for (int j = i; j < nums.size(); j++)
        {
            sum += nums[j];
            if (sum == k) count++;
        }
    }

    return count;
}

int main()
{
    vector<int> nums = {1, 1, 1};

    cout << subarraySum(nums, 2) << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <unordered_map>

using namespace std;

int subarraySum(vector<int> &nums, int k)
{
    unordered_map<int, int> prefixCount;
    prefixCount[0] = 1; // empty prefix, sum 0, seen once

    int sum = 0;
    int count = 0;

    for (int num : nums)
    {
        sum += num;
        count += prefixCount[sum - k];
        prefixCount[sum]++;
    }

    return count;
}

int main()
{
    vector<int> nums = {1, 1, 1};

    cout << subarraySum(nums, 2) << endl;

    return 0;
}

